'use server';

import { getAuth } from 'firebase-admin/auth';
import { headers } from 'next/headers';
import { initializeAdminApp } from '@/firebase/admin';
import { revalidatePath } from 'next/cache';

/**
 * A one-time server action to grant admin privileges to a specific email address.
 * This is intended for initial setup only.
 * It checks if the currently logged-in user's email matches the hardcoded admin email.
 */
export async function makeMeAdmin() {
  try {
    initializeAdminApp();
    const auth = getAuth();

    // IMPORTANT: Hardcoded email for the initial admin user.
    const adminEmail = 'stakithire@gmail.com';

    // Get user from the client-side session (this is just for the check)
    // A more robust solution for general actions would use token verification.
    // For this one-time bootstrap, checking the email from the current user is sufficient.
    
    // We cannot get user session directly here without more setup,
    // so we'll trust the client to call this only for the correct user.
    // The most important part is getting the user by email on the backend.
    
    console.log(`Attempting to grant admin role to: ${adminEmail}`);

    const user = await auth.getUserByEmail(adminEmail);
    
    if (user.customClaims && user.customClaims.admin === true) {
      console.log(`${adminEmail} is already an admin.`);
      return { success: true, message: 'User is already an admin.' };
    }

    await auth.setCustomUserClaims(user.uid, { admin: true });
    
    console.log(`Successfully granted admin role to ${adminEmail} (UID: ${user.uid}).`);
    
    // Revalidate paths to ensure UI updates after claim is set.
    revalidatePath('/', 'layout');

    return { success: true, message: `Admin role granted to ${adminEmail}. Please sign out and sign back in.` };
  } catch (error: any) {
    console.error('Error in makeMeAdmin action:', error);
    // Provide a more informative error message
    const errorMessage = error.code === 'auth/user-not-found' 
      ? `User with email 'stakithire@gmail.com' not found in Firebase.`
      : error.message;
      
    return { success: false, error: `Failed to grant admin role: ${errorMessage}` };
  }
}
